function computeRiskRating(documentModel) {
  const total2 = documentModel.kpis?.total_responses || 0;
  if (total2 === 0) return { rating: "Not yet assessable", basis: "No responses collected yet." };
  const negativeEntry = (documentModel.findings?.sentiment || []).find((s) => s.label === "negative");
  const negativePct = negativeEntry ? Math.round(negativeEntry.n / total2 * 100) : 0;
  const flaggedPct = total2 > 0 ? Math.round((documentModel.data_quality?.flagged_response_count || 0) / total2 * 100) : 0;
  let rating = "Standard";
  if (negativePct >= 25 || flaggedPct >= 10) rating = "Elevated";
  if (negativePct >= 40 || flaggedPct >= 20) rating = "High";
  return { rating, basis: `${negativePct}% negative sentiment, ${flaggedPct}% flagged responses (data-quality basis).` };
}
