// src/ai-report-assistant.js
async function askReportQuestion(env, { documentModel, question }) {
  if (!question || !question.trim()) {
    throw new Error("question is required");
  }
  if (documentModel.kpis.total_responses === 0) {
    return { answer: "This report has no responses yet, so there is no data to answer questions about.", grounded: false };
  }
  const context = {
    metadata: documentModel.metadata,
    kpis: documentModel.kpis,
    demographics: documentModel.demographics,
    findings: documentModel.findings,
    data_quality: documentModel.data_quality,
    recommendations: documentModel.recommendations,
    narrative: documentModel.narrative || null
  };
  const prompt = `You are answering a question about ONE specific research report. You must answer ONLY using the REPORT DATA below \u2014 never general knowledge, never information about any other report or organization.

If the data below does not contain enough information to answer the question, say so explicitly (e.g. "This report does not include regional breakdowns for that indicator") rather than guessing, estimating, or inventing a number.

REPORT DATA:
${JSON.stringify(context)}

QUESTION: ${question}

Respond with a direct, concise answer. Use 2-4 sentences unless the question specifically asks for a list or comparison, in which case use a short list. Reference specific numbers from the data when relevant.`;
  const claudeResp = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: { "x-api-key": env.ANTHROPIC_API_KEY, "anthropic-version": "2023-06-01", "Content-Type": "application/json" },
    body: JSON.stringify({ model: "claude-sonnet-5", max_tokens: 800, messages: [{ role: "user", content: prompt }] })
  });
  if (!claudeResp.ok) {
    throw new Error(`Claude API returned HTTP ${claudeResp.status} (${claudeResp.statusText || "error"})`);
  }
  const data = await claudeResp.json();
  const answer = (data.content || []).map((c) => c.text || "").join("").trim();
  if (!answer) throw new Error("Claude returned an empty response");
  return { answer, grounded: true };
}
__name(askReportQuestion, "askReportQuestion");

// src/report-dashboard.js
async function buildDrilldown(env, { organizationId, campaignId, region, gender: gender3, ageBracket }) {
  const conditions = ["c.organization_id = ?"];
  const binds = [organizationId];
  if (campaignId) {
    conditions.push("c.id = ?");
    binds.push(campaignId);
  }
  if (region) {
    conditions.push("resp.region = ?");
    binds.push(region);
  }
  const needsDemJoin = !!(gender3 || ageBracket);
  let demJoin = "";
  if (needsDemJoin) {
    demJoin = "LEFT JOIN respondent_demographics dem ON dem.respondent_id = resp.id";
    if (gender3) {
      conditions.push("dem.gender = ?");
      binds.push(gender3);
    }
    if (ageBracket) {
      conditions.push("dem.age_bracket = ?");
      binds.push(ageBracket);
    }
  }
  const whereClause = conditions.join(" AND ");
  const totalResponses6 = await env.DB.prepare(
    `SELECT COUNT(*) as n FROM responses r JOIN campaigns c ON r.campaign_id = c.id JOIN respondents resp ON r.respondent_id = resp.id ${demJoin} WHERE ${whereClause}`
  ).bind(...binds).first();
  const { results: sentimentRows2 } = await env.DB.prepare(
    `SELECT COALESCE(r.overall_sentiment, 'Not yet analyzed') as label, COUNT(*) as n
     FROM responses r JOIN campaigns c ON r.campaign_id = c.id JOIN respondents resp ON r.respondent_id = resp.id ${demJoin}
     WHERE ${whereClause} GROUP BY label`
  ).bind(...binds).all();
  const { results: regionRows2 } = await env.DB.prepare(
    `SELECT COALESCE(NULLIF(TRIM(resp.region), ''), 'Not provided') as label, COUNT(*) as n
     FROM responses r JOIN campaigns c ON r.campaign_id = c.id JOIN respondents resp ON r.respondent_id = resp.id ${demJoin}
     WHERE ${whereClause} GROUP BY label ORDER BY n DESC LIMIT 15`
  ).bind(...binds).all();
  return {
    filters_applied: { region: region || null, gender: gender3 || null, age_bracket: ageBracket || null },
    total_responses: totalResponses6.n,
    sentiment: sentimentRows2,
    regions: regionRows2
  };
}
__name(buildDrilldown, "buildDrilldown");
async function buildComparison(env, reportRows) {
  return reportRows.map((row) => {
    const dm = JSON.parse(row.document_model_json);
    return {
      report_id: row.id,
      organization_name: dm.metadata.organization_name,
      campaign_name: dm.metadata.campaign_name,
      generated_at: dm.metadata.generated_at,
      kpis: dm.kpis,
      sentiment: dm.findings.sentiment
    };
  });
}
__name(buildComparison, "buildComparison");

