        const responseId = newId("response");
        await env.DB.prepare(`INSERT INTO responses (id, campaign_id, respondent_id, channel, status, completed_at) VALUES (?, ?, ?, 'csv_import', 'completed', datetime('now'))`).bind(responseId, campaignId, respondentId).run();
