          const colIdx = headers.indexOf("q" + (qi + 1));
          if (colIdx < 0 || !cols[colIdx]) continue;
          await env.DB.prepare("INSERT INTO answers (id, response_id, question_id, answer_text) VALUES (?, ?, ?, ?)").bind(newId("answer"), responseId, questions[qi].id, cols[colIdx]).run();
